$(document).ready(function(){const page=window.location.pathname.split('/').pop()||'index.html';$('.nav-link').each(function(){const href=$(this).attr('href');if(href===page)$(this).addClass('active');});$('a[href^="#"]').on('click',function(e){const target=$(this.getAttribute('href'));if(target.length){e.preventDefault();$('html, body').animate({scrollTop:target.offset().top-75},600);}});if('IntersectionObserver'in window){const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;if(img.dataset.src){img.src=img.dataset.src;img.classList.add('loaded');observer.unobserve(img);}}});},{rootMargin:'200px'});document.querySelectorAll('img.lazy').forEach(img=>observer.observe(img));}else{document.querySelectorAll('img.lazy').forEach(img=>{if(img.dataset.src){img.src=img.dataset.src;img.classList.add('loaded');}});}
$(document).on('click','.gallery-thumb',function(){const src=$(this).data('large')||$(this).attr('src');const alt=$(this).attr('alt')||'';$('#veve-lightbox img').attr({src:src,alt:alt});$('#veve-lightbox').addClass('active');});$('#veve-lightbox .close-btn, #veve-lightbox').on('click',function(e){if($(e.target).is('#veve-lightbox')||$(e.target).is('.close-btn')){$('#veve-lightbox').removeClass('active');}});$(document).on('keydown',function(e){if(e.key==='Escape')$('#veve-lightbox').removeClass('active');});let cartCount=0;$(document).on('click','.veve-add-to-cart',function(){cartCount++;$('#veve-cart-count').text(cartCount).show();const btn=$(this);btn.text('✓ Přidáno').addClass('btn-success').removeClass('btn-veve');setTimeout(()=>btn.text('Do košíku').removeClass('btn-success').addClass('btn-veve'),1500);});$(document).on('click','.veve-filter-btn',function(){const cat=$(this).data('cat');$('.veve-filter-btn').removeClass('active btn-veve').addClass('btn-outline-secondary');$(this).removeClass('btn-outline-secondary').addClass('active btn-veve');if(cat==='vse'){$('.product-item').show();}else{$('.product-item').hide().filter('[data-cat="'+cat+'"]').show();}});$('#veve-contact-form').on('submit',function(e){e.preventDefault();$('#veve-form-success').removeClass('d-none').hide().fadeIn();this.reset();setTimeout(()=>$('#veve-form-success').fadeOut(),4000);});});